60	- (void)loadView {
61	    [super loadView];
62	    
63	    self.fd_prefersNavigationBarHidden = YES;
64	    self.isPopRecognizerEnabled = NO;
65	    self.seconds = kDeleteDuration;
66	    [self initSubviews];
