82	- (void)initSubviews {
83	    if ([CTMediator isMona]) {
84	        [self goToStep3];
85	        return;
86	    }
87	    [self.view addSubview:self.step1View];
88	    [self.step1View mas_makeConstraints:^(MASConstraintMaker *make) {
89	        make.edges.equalTo(self.view);
90	    }];
91	    @weakify(self)
92	    [[self.step1View.lockButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
93	        @strongify(self)
94	        if(CTMediator.carState.extState.vehicleMode == XPCarExtVehicleModeShow){
95	            [QMUIAlertController showAlertWithTitle:@"展车模式中，请确认车内乘客离开后再锁车" message:nil leftButtionTitle:@"取消" leftButtonType:QMUIAlertActionStyleCancel leftAction:^(__kindof QMUIAlertController * _Nonnull alertVC, QMUIAlertAction * _Nonnull action) {
96	                
97	            } rightButtonTitle:@"立即锁车" rightButtonType:QMUIAlertActionStyleDefault rightAction:^(__kindof QMUIAlertController * _Nonnull alertVC, QMUIAlertAction * _Nonnull action) {
98	                @strongify(self)
99	                [self handleLockButton];
100	            }];
101	            return;
102	        }
103	        [self handleLockButton];
104	    }];
105	
106	    [[self.step1View.backButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
107	        @strongify(self)
108	        [self.navigationController popViewControllerAnimated:YES];
109	    }];
110	}
