112	- (void)handleLockButton{
113	    if([self judgeCanLock]) {
114	        self.step1View.lockButton.enabled = NO;
115	        [XPToast showLoadingMessage:@"锁车中..." hasMask:YES];
116	        [self lockButtonTouch];
117	    }
118	}
119	
120	- (void)lockButtonTouch{
121	    [self lockButtonTouch2nd];
122	}
123	
124	- (void)lockButtonTouch2nd{
125	    [[XPVehicleSDK.shared.vehicleManager currentVehicle]
126	     sendCommand:XPVehicleCommandLock success:^{
127	        self.step1View.lockButton.enabled = YES;
128	        DLogTagInfo(kBLEKeyTag, @"锁车成功，刷新整车状态，并跳转到删除授权第二步");
129	        [[XPVehicleSDK.shared.vehicleManager currentVehicle]
130	                   sendCommand:XPVehicleCommandForceUploadCarInfo extParams:nil success:^{
131	                [XPToast dismissLoadingMessage];
132	                [self.step1View removeFromSuperview];
133	                [self goToStep2];
134	        } failed:^(XPVehicleError * _Nonnull error) {
135	            [XPToast dismissLoadingMessage];
136	            [self.step1View removeFromSuperview];
137	            [self goToStep2];
138	        }];
139	    } failed:^(XPVehicleError * error) {
140	        self.step1View.lockButton.enabled = YES;
141	        [XPToast dismissLoadingMessage];
142	        [XPToast removePreviewToastOnView];
143	        dispatch_async(dispatch_get_main_queue(), ^{
144	            NSString *title = @"锁车失败，请检查";
145	            NSString *message = @"1. 请确保主驾无人\n2. 车门及前后盖已关闭\n3. 挡位置于P挡\n4. 车辆网络良好";
146	            if(error.channel == XPVehicleChannelTCP && error.code == 12){
147	                title = error.msg;
148	                message = nil;
149	            }
150	            [QMUIAlertController showAlertWithTitle:title
151	                                            message:message
152	                                   leftButtionTitle:nil
153	                                     leftButtonType:QMUIAlertActionStyleCancel
154	                                         leftAction:nil
155	                                   rightButtonTitle:@"确认"
156	                                    rightButtonType:QMUIAlertActionStyleDefault
157	                                        rightAction:nil];
158	        });
159	        DLogTagInfo(kBLEKeyTag, @"锁车失败:%@", error.msg);
160	    }];
161	}
