172	- (void)goToStep2 {
173	    [self.view addSubview:self.step2View];
174	    [self.step2View mas_makeConstraints:^(MASConstraintMaker *make) {
175	        make.edges.equalTo(self.view);
176	    }];
177	    
178	    __weak typeof(self) weakSelf = self;
179	    self.deleteTimer = [NSTimer bk_scheduledTimerWithTimeInterval:3 block:^(NSTimer *timer) {
180	        [[weakSelf.checkCarStatusViewModel.checkVehicleStatusCommand execute:@{@"vin":weakSelf.vin?:@"",
181	                                                             @"operType":@(XPKeyCardOperationTypeDelete),
182	                                                             @"cardType":@(XPBLEKeyCardType_BLEKey),
183	                                                             @"remoteLockResult":@(CTMediator.carState.doorInfo.driver_door_lock_st? 1:2)
184	        }] subscribeNext:^(id  _Nullable x) {
185	            
186	        } error:^(NSError * _Nullable error) {
187	            DLogTagInfo(kBLEKeyTag, @"检车车况失败%@", error);
188	        } completed:^{
189	            if(CTMediator.carState.powerInfo.car_igon_state != 0) {
190	                DLogTagInfo(kBLEKeyTag, @"检车车况正常，但车辆处于上电状态，跳转到失败界面");
191	                [weakSelf.deleteTimer invalidate];
192	                weakSelf.deleteTimer = nil;
193	                [weakSelf.step2View removeFromSuperview];
194	
195	                [weakSelf goToFailPageWithTips:@"车辆已上电，请确认锁车下电后重试"];
196	            } else {
197	                DLogTagInfo(kBLEKeyTag, @"检车车况正常，跳转到解除车辆授权第三步");
198	                [weakSelf.deleteTimer invalidate];
199	                weakSelf.deleteTimer = nil;
200	                [weakSelf.step2View removeFromSuperview];
201	                
202	                [weakSelf goToStep3];
203	            }
204	        }];
205	    } repeats:YES];
206	}
