208	- (void)goToStep3 {
209	    [self.view addSubview:self.step3View];
210	    [self.step3View mas_makeConstraints:^(MASConstraintMaker *make) {
211	        make.edges.equalTo(self.view);
212	    }];
213	    self.step3View.titleLabel.text = @"正在解除车辆授权";
214	    self.step3View.bleImageView.image = [UIImage imageNamed:@"ic_releaseauth"];
215	    [self.step3View.animationView stop];
216	    [self.step3View.animationView setCompatibleAnimation:[[CompatibleAnimation alloc] initWithName:@"createBleKeyStep2" subdirectory:nil bundle:NSBundle.mainBundle]];
217	    self.step3View.animationView.loopAnimationCount = -1;
218	    [self.step3View.animationView play];
219	    
220	    [self checkIsDeleteSuccessAfterDoorIsLocked];
221	    [self deleteWarranty];
222	}
