224	- (void)deleteWarranty {
225	    if (self.isAuthorizedPerson) {
226	        @weakify(self);
227	        [[CTMediator deleteGrantedVehicleWithVin:self.vin] subscribeNext:^(id  _Nullable x) {
228	        } error:^(NSError * _Nullable error) {
229	            DLogTagInfo(kBLEKeyTag, @"删除授权失败:%@", error);
230	        } completed:^{
231	            @strongify(self);
232	            [XPToast showMessage:@"已解绑车辆"];
233	            [self refreshAuthList];
234	            [XPVehicleSDKDealTool clearCacheWhenAuthorizationCanceledWithVin:self.vin];
235	            
236	            [self refreshCarInfosAndUserInfo];
237	            //跳至车控页
238	            [CTMediator.tabBarController switchToTab:XPTabBarIndexCar];
239	            //退出到主页
240	            [CTMediator.currentTabBarNavigation popToRootViewControllerAnimated:YES];
241	        }];
242	    } else {
243	        @weakify(self);
244	        [[self.cancelWarrantyViewModel.requestCancelDriverCommand execute:nil] subscribeNext:^(id  _Nullable x) {
245	        } error:^(NSError * _Nullable error) {
246	            DLogTagInfo(kBLEKeyTag, @"删除授权失败:%@", error);
247	        } completed:^{
248	            @strongify(self);
249	            [XPToast showMessage:@"已解除授权"];
250	            DLogTagInfo(kBLEKeyTag, @"解除授权成功");
251	            [self refreshAuthList];
252	            for (UIViewController *vc in self.navigationController.viewControllers) {
253	                if([vc isKindOfClass:XPNewCarPermissionListViewController.class]) {
254	                    [self.navigationController popToViewController:vc animated:YES];
255	                    break;
256	                }
257	            }
258	        }];
259	    }
260	}
