262	- (void)refreshCarInfosAndUserInfo {
263	    @weakify(self)
264	    [XPVehicleSDK.shared.vehicleManager requestVehicleInfo: ^{
265	        @strongify(self)
266	        DLogTagInfo(kBLEKeyTag, @"车辆授权，刷新车辆数据成功");
267	        [[CTMediator refresh] subscribeCompleted:^{
268	            DLogTagInfo(kBLEKeyTag, @"车辆授权，刷新个人信息成功");
269	        }];
270	        [NSNotificationCenter.defaultCenter postNotificationName:XPCarPermissionNotificaiton object:nil];
271	    } failed :^(XPVehicleError * error) {
272	        DLogTagInfo(kBLEKeyTag, @"车辆授权，刷新车辆数据失败");
273	    }];
274	}
