283	- (void)checkIsDeleteSuccessAfterDoorIsLocked {
284	    self.step2View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)self.seconds];
285	    self.step2View.sLabel.text = @"s";
286	    self.step3View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)self.seconds];
287	    self.step3View.sLabel.text = @"s";
288	    __weak typeof(self) weakSelf = self;
289	    self.secondsTimer = [NSTimer bk_scheduledTimerWithTimeInterval:1 block:^(NSTimer *timer) {
290	        weakSelf.seconds--;
291	        weakSelf.step2View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)weakSelf.seconds];
292	        weakSelf.step3View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)weakSelf.seconds];
293	        if(weakSelf.seconds <= 0) {
294	            [weakSelf.secondsTimer invalidate];
295	            weakSelf.secondsTimer = nil;
296	            if(!weakSelf.isDeleteSuccess) {
297	                DLogTagInfo(kBLEKeyTag, @"解除授权%ld秒已到，未成功，跳转到失败页面", (long)kDeleteDuration);
298	                [weakSelf goToFailPageWithTips:@"抱歉发生了错误，请稍后重试"];
299	            }
300	        }
301	    } repeats:YES];
302	}
