304	- (void)goToFailPageWithTips:(NSString *)tips {
305	    for (UIView *subview in self.view.subviews) {
306	        [subview removeFromSuperview];
307	    }
308	    
309	    [self.view addSubview:self.errorView];
310	    [self.errorView mas_makeConstraints:^(MASConstraintMaker *make) {
311	        make.edges.equalTo(self.view);
312	    }];
313	    self.errorView.titleLabel.text = @"解除授权失败";
314	    self.errorView.descLabel.text = tips;
315	    @weakify(self);
316	    [[self.errorView.closeButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
317	        @strongify(self);
318	        [self.navigationController popViewControllerAnimated:YES];
319	    }];
320	}
