322	- (void)showFailToLockAlertWithError:(NSError *)error{
323	    //主线程处理UI
324	    dispatch_async(dispatch_get_main_queue(), ^{
325	        NSString *title = @"锁车失败，请检查";
326	        NSString *message = @"1. 请确保主驾无人\n2. 车门及前后盖已关闭\n3. 挡位置于P挡\n4. 车辆网络良好";
327	        if([error.userInfo[@"code"] integerValue] == MQTTResponseCodeSomeoneIsControlingCar){
328	            title = error.userInfo[NSLocalizedFailureReasonErrorKey];
329	            message = nil;
330	        }
331	        [QMUIAlertController showAlertWithTitle:title
332	                                        message:message
333	                               leftButtionTitle:nil
334	                                 leftButtonType:QMUIAlertActionStyleCancel
335	                                     leftAction:nil
336	                               rightButtonTitle:@"确认"
337	                                rightButtonType:QMUIAlertActionStyleDefault
338	                                    rightAction:nil];
339	    });
340	}
