118	- (RACSignal*)tryToConnectBLE {
119	    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
120	        
121	        RACCompoundDisposable *disposable = [RACCompoundDisposable compoundDisposable];
122	        [disposable addDisposable:[[RACSignal.never timeout:10 onScheduler:RACScheduler.scheduler] subscribeError:^(NSError * _Nullable error) {
123	            [subscriber sendError:[NSError errorWithDomain:@"timeout" code:-1 userInfo:@{}]];
124	        }]];
125	        [XPBLEHandlerManager.manager startBleConnectAndAuthComplete:^(NSError *error) {
126	            if (error) {
