296	- (void)sendCertKeyVerifyCommand:(XPTBoxCommand)cmd {
297	    if (![XPBLEKeyManager.instance isSafeKeyOrCertKeyExisted]) {
298	        DLogTagWarn(kBLEKeyTag, @"安全钥匙和证书钥匙都不存在");
299	        return;
300	    }
301	    
302	    if ([[XPBLEHandlerManager manager] commuicateBleIsSendingBleCommand] && CTMediator.isE28) {
303	        DLogTagWarn(kBLEKeyTag, @"当前正在发送蓝牙车控指令,直接返回不做处理");
304	        return;
305	    }
306	    
307	    NSString *ifaaMsg = [CertKeyMessage getOneMessageWithVin:CTMediator.vin].message;
308	    DLogTagError_if([NSString isEmptyWithString:ifaaMsg], kBLEKeyTag, @"ifaaMsg is nil");
309	    __CHECK(![NSString isEmptyWithString:ifaaMsg])
310	    
311	    @weakify(self)
312	    NSMutableDictionary *params = [NSMutableDictionary dictionary];
313	    if (XPVehicleSDK.currentAbilityConfig.bleKeyVersion == BleKeyProtocolVesionV3) {
314	        uint8_t controlId = [XPBLEControlIdFactory getControlId].unsignedShortValue;
315	        params[kBleKeyV3ControlIdKey] = @(controlId);
316	        NSMutableArray *dataArray = [NSMutableArray array];
317	        [dataArray addObject:@(cmd)];
318	        params[kBleKeyV3ControlDataKey] = [dataArray copy];
319	    } else {
320	        params[@"ifaa"] = ifaaMsg;
321	        params[@"cmd"] = @(cmd);
322	    }
323	    
324	    [XPBLEHandlerManager.manager sendRkeControlCertMessage:params complete:^(NSError * _Nonnull error) {
325	        if (error) {
326	            DLogTagError(kBLEKeyTag, @"%@",error);
327	            [XPToast showMessage:XP_CAR_CONTROL_LOCALIZED_STRING(@"parking_back_to_homepage_tip", nil)];
328	        } else {
329	            DLogTagInfo(kBLEKeyTag, @"send ble command success");
330	            [self waitingForBiometricResults];
331	        }
332	    }];
