96	- (void)setUpAirClockSettingsInfoByTimeValue:(NSString *)timeValue scheduleType:(NSInteger)scheduleType{
97	    
98	    if (![[NetworkMonitorManager sharedManager] isReachable]) {
99	        [XPToast showMessage:XP_CAR_CONTROL_LOCALIZED_STRING(@"air_web_not_connect_tip", nil)];
100	        return;
101	    }
102	
103	    //[XPToast showLoadingMessage:XP_COMMON_MODULE_LOCALIZED_STRING(@"loading", nil)];
104	    
105	    XPCarClockOperateInfo *info = [[XPCarClockOperateInfo alloc] init];
106	    info.function = XPCarClockFunctionType_Air;
107	    info.operateType = XPCarClockOperateType_Setup;
108	    info.idd = 1;
109	    info.valid = 1;
110	    info.time = timeValue;
111	    
112	    XPCarClockSchedule s;
113	    s.r = 0;
114	    s.Mon = (scheduleType==0)?0:1;
115	    s.Tues = (scheduleType==0)?0:1;
116	    s.Wed = (scheduleType==0)?0:1;
117	    s.Thur = (scheduleType==0)?0:1;
118	    s.Fri = (scheduleType==0)?0:1;
119	    s.Sat = (scheduleType==0)?0:1;
120	    s.Sun = (scheduleType==0)?0:1;
121	    info.schedule = s;
122	    
123	    [self dimissAppointmentVC];
124	
125	    @weakify(self);
