197	- (NSDictionary *)convertScheduleModelToDic:(XPScheduleModel *)model {
198	    NSString *hourStr = @"";
199	    NSString *minStr = @"";
200	    if (model.beginHour > 9) {
201	        hourStr = [NSString stringWithFormat:@"%ld", (long)model.beginHour];
202	    } else {
203	        hourStr = [NSString stringWithFormat:@"0%ld", (long)model.beginHour];
204	    }
205	    if (model.beginMinute > 9) {
206	        minStr = [NSString stringWithFormat:@"%ld", (long)model.beginMinute];
207	    } else {
208	        minStr = [NSString stringWithFormat:@"0%ld", (long)model.beginMinute];
209	    }
210	    NSString *timeStr = [NSString stringWithFormat:@"%@:%@", hourStr, minStr];
211	    
212	    return @{@"id" : @(model.id), @"time" : timeStr, @"schedule" : @(model.schedule), @"valid" : @(model.state)};
