216	    NSArray *tempWeek = @[@"7",@"1",@"2",@"3",@"4",@"5",@"6"];
217	    NSCalendar *calendar = [[NSCalendar alloc] initWithCalendarIdentifier:NSCalendarIdentifierGregorian];
218	    
219	    NSDateComponents *comps = [[NSDateComponents alloc] init];
220	    
221	    NSInteger unitFlags = NSCalendarUnitYear |NSCalendarUnitMonth | NSCalendarUnitDay |NSCalendarUnitWeekday | NSCalendarUnitHour |NSCalendarUnitMinute |NSCalendarUnitSecond;
222	    
223	    comps = [calendar components:unitFlags fromDate:date];
224	    NSInteger week = [comps weekday];
225	    //  1、2、3、4、5、6、7 分别对应 周一、周二、周三、周四、周五、周六、周日
226	    return  [tempWeek[week-1] integerValue] ;
