259	- (void)checkConnectionStatus:(AFNetworkReachabilityStatus)netStatus
260	{
261	    if (netStatus == AFNetworkReachabilityStatusReachableViaWiFi)
262	    {
263	        NSString *ipAddr = [XPFileTransferTools getIPAddress];
264	        if (ipAddr && [ipAddr hasPrefix:HOST_PREFIX]) {
265	            //与服务器共享热点的网段一样，则表明已经连接上服务端共享的Wifi热点
266	            DLogTagInfo(kFileTransferUrgentTag, @"已连接到服务端共享的热点！");
267	            if (!self.isConnectedToAp) {
268	                DLogTagInfo(kFileTransferUrgentTag, @"步骤三：已连接想要的wifi");
269	                self.isConnectedToAp = YES; //设置连接ap状态
270	                
271	                //之前未连接到热点，则初始化所有状态
272	                if (!self.hasSetUDP) {
273	                    [self backFromSetting];
274	                }
275	                //[self initWhileConnectToAp];
276	            }
277	        } else {
278	            //wifi下，但非服务器共享热点的网段，则需要主动断开连接
279	            DLogTagInfo(kFileTransferUrgentTag, @"wifi下，但非服务器共享热点的网段，则需要主动断开连接");
280	            self.isConnectedToAp = NO;
281	            
282	            if (self.hasConnectServer) {
283	                //第三页面如果不是我要的wifi
284	                [self showWifiError];
285	            }
286	            
287	        }
288	    } else {
