385	- (void)setupUdpSocket
386	{
387	    if (!self.udpSocket) {
388	        self.udpSocket = [[GCDAsyncUdpSocket alloc] initWithDelegate:self delegateQueue:dispatch_get_global_queue(0, 0)];
389	    }
390	    
391	    [self bindUdpPortAndSync];
392	}
393	
394	- (void)bindUdpPortAndSync
395	{
396	    self.udpListenPort = PORT_UDP_LISTEN;
397	    
398	    NSError *error = nil;
399	    if ([self.udpSocket bindToPort:self.udpListenPort error:&error]) {
400	        //每次连接到ap，都需要尝试重新绑定端口，防止端口被释放（比如app在后台停留3分钟）
401	        DLogTagInfo(kFileTransferUrgentTag, @"UDP绑定端口成功 - %@，端口号（%@）", error, @(self.udpListenPort));
402	    } else {
403	        DLogTagInfo(kFileTransferUrgentTag, @"UDP绑定端口失败 - %@，端口号（%@）", error, @(self.udpListenPort));
404	        
405	        if ([self.udpSocket bindToPort:self.udpListenPort+1 error:&error]) {
406	            self.udpListenPort = self.udpListenPort + 1;
407	            //每次连接到ap，都需要尝试重新绑定端口，防止端口被释放（比如app在后台停留3分钟）
408	            DLogTagInfo(kFileTransferUrgentTag, @"UDP绑定端口成功2 - %@，端口号（%@）", error, @(self.udpListenPort));
409	        } else {
410	            DLogTagInfo(kFileTransferUrgentTag, @"UDP绑定端口失败2 - %@，端口号（%@）", error, @(self.udpListenPort));
411	            
412	        }
413	        
414	        
415	    }
416	    
417	    //开启UDP广播，作为获取服务器IP备选方案，主方案是直接获取路由地址，但有时会有延迟
418	    NSError *broadcastError = nil;
419	    if (![self.udpSocket enableBroadcast:YES error:&broadcastError]) {
420	        DLogTagInfo(kFileTransferUrgentTag, @"开启UDP广播失败 - %@", broadcastError);
421	    }
422	    if (![self.udpSocket beginReceiving:&error])
423	    {
424	        DLogTagInfo(kFileTransferUrgentTag, @"UDP绑定后，开启接收数据失败 - %@", error);
425	        return;
426	    }
427	    
428	    //第一步:发送握手信息
429	    [self sendUdpResponseMessage:YES];
430	}
431	
432	- (void)sendUdpResponseMessage:(BOOL)isAccept
433	{
434	    //isAccept = YES;
435	    //构造响应消息
436	    XPFileTransferMessage *udpMsg = [self genUdpMessageModel];
437	    udpMsg.action = isAccept ? XPFileTransferMessageActionClientToServerAccept : XPFileTransferMessageActionClientToServerReject;
438	    
439	    if (!isAccept) {
440	        //拒绝接收文件
441	        //只需要发送一次响应消息
442	        DLogTagInfo(kFileTransferUrgentTag, @"拒绝接收文件");
443	        [self sendUdpMessage:[udpMsg jsonString] withTag:udpMsg.action];
444	    } else {
445	        //准备接收文件
446	        dispatch_async(dispatch_get_global_queue(0, 0), ^{
447	            //每隔2秒，发送一次接收文件的响应消息
448	            NSUInteger udpMsgCount = 1;
449	            //接收进程未结束的情况下，如果发送握手消息后，服务端未返回响应消息，则每隔2秒发送一次握手消息
450	            while (!self.isUdpHandshakeFinished) {
451	                DLogTagInfo(kFileTransferUrgentTag, @"准备接收文件，发送次数->%@", @(udpMsgCount));
452	                [self sendUdpMessage:[udpMsg jsonString] withTag:udpMsg.action];
453	                if (udpMsgCount>200) {
454	                    self.isUdpHandshakeFinished = YES;
455	                }
456	                udpMsgCount++;
457	                //休眠2秒
458	                sleep(2);
459	            }
460	        });
461	        
462	    }
463	}
