719	- (NSString *)fomateJsonWithDictionary:(NSDictionary *)dict {
720	
721	    NSError *error;
722	    NSData *jsonData = [NSJSONSerialization dataWithJSONObject:dict options:NSJSONWritingPrettyPrinted error:&error];
723	    NSString *jsonString;
724	    if (!jsonData) {
725	        NSLog(@"%@",error);
726	    }else{
727	        jsonString = [[NSString alloc]initWithData:jsonData encoding:NSUTF8StringEncoding];
728	    }
729	    NSMutableString *mutStr = [NSMutableString stringWithString:jsonString];
730	    NSRange range = {0,jsonString.length};
731	    //去掉字符串中的空格
732	    [mutStr replaceOccurrencesOfString:@" " withString:@"" options:NSLiteralSearch range:range];
733	    
734	    NSRange range2 = {0,mutStr.length};
735	    //去掉字符串中换行
736	    [mutStr replaceOccurrencesOfString:@"\n" withString:@"" options:NSLiteralSearch range:range2];
737	    return mutStr;
738	
739	}
