756	- (void)udpSocket:(GCDAsyncUdpSocket *)sock didReceiveData:(NSData *)data fromAddress:(NSData *)address withFilterContext:(id)filterContext
757	{
758	    NSString *host = nil;
759	    uint16_t port = 0;
760	    [GCDAsyncUdpSocket getHost:&host port:&port fromAddress:address];
761	    
762	    
763	    //接收到服务端的udp消息后，记录ip
764	    self.serverIp = [NSString stringWithFormat:@"%@",host];
765	    
766	    NSString *msg = [[NSString alloc] initWithData:data encoding:NSUTF8StringEncoding];
767	    DLogTagInfo(kFileTransferUrgentTag, @"步骤五：接收到服务端的UDP消息，ip地址->%@，port->%u，内容->%@", host, port, msg);
768	    
769	    NSDictionary *temp = [self turnStringToDictionary:msg];
770	    
771	    
772	    XPFileTransferMessage *msgModel = [XPFileTransferMessage yy_modelWithJSON:msg];
773	    
774	    if (msgModel.action == XPFileTransferMessageActionClientToServerAccept) {
775	
776	        //服务端响应客户端的文件请求udp消息
777	        DLogTagInfo(kFileTransferUrgentTag, @"步骤五：大屏将接受到的消息回复给手机端0");
778	        //第二步：接收到ip 和 port
779	        //self.isUdpHandshakeFinished = YES;
780	        
781	    }
782	    if (msgModel.action == XPFileTransferMessageActionServerToClientAccept) {
783	        //服务端响应客户端的文件请求udp消息
784	        DLogTagInfo(kFileTransferUrgentTag, @"步骤五：大屏将Socket Server 信息发送给手机1");
785	        
786	        if (self.udpSocket) {
787	            DLogTagInfo(kFileTransferUrgentTag, @"步骤五-1：收到1就释放UDP");
788	            [self.udpSocket close];
789	            self.udpSocket = nil;
790	        }
791	
792	        
793	        //第二步：接收到ip 和 port
794	        self.isUdpHandshakeFinished = YES;
795	        if (self.hasConnectServer) {
796	            return;
797	        }
798	        
799	        NSDictionary *dicData = [self dictionaryForJsonData:data];
800	        NSString *portStr = [dicData valueForKey:@"port"];
801	        port = [portStr intValue];
802	        self.tcpPort = port;
803	        
804	        //显示Step3;
805	        dispatch_async(dispatch_get_main_queue(), ^{
806	            DLogTagInfo(kFileTransferUrgentTag, @"步骤六：接收到TCP端口号%ld，IP%@，去到第三步",(long)self.tcpPort,self.serverIp);
807	           // [self.viewTwo removeFromSuperview];
808	            if (self.viewTwo.superview) {
809	                [self.viewTwo removeFromSuperview];
810	            }
811	            if (self.viewTwoLock) {
812	                [self.viewTwoLock removeFromSuperview];
813	            }
814	            if (self.viewThree.superview) {
815	                return;
816	            }
817	            CGFloat topOffset = kStatusBarHeight+kNavigationBarHeight;
818	            self.viewThree = [[UrgentViewThree alloc] initWithFrame:CGRectMake(0, topOffset, kScreenWidth, kScreenHeight-topOffset)];
819	            self.viewThree.delegate = self;
820	            if (self.chooseLock) {
821	                [self.viewThree refreshToLockButton];
822	            }
823	            [self.textBar setTitle:@"应急钥匙"];
824	            [self.view addSubview:self.viewThree];
825	            //第三步：连接socket
826	            self.hasConnectServer = YES;
827	            
828	        });
829	        
830	    }
831	    
