110	- (void)airHeatUpOrDownLoadingMonitor {
111	    @weakify(self);
112	    [[AirCtrlStateHelper sharedInstance].airHeatUpSignal.deliverOnMainThread subscribeNext:^(NSNumber * _Nullable x) {
113	        @strongify(self);
114	        if ([x boolValue]) {
115	            if (self.carState.seatState.driverSeatHeat <= 0) {
116	                self.driverSeatButton.heatButton.loading = YES;
117	            }
118	            if (self.carState.seatState.passengerSeatHeat <= 0) {
119	                self.passengerSeatButton.heatButton.loading = YES;
120	            }
121	            if (self.carState.seatState.leftRearSeatHeat <= 0) {
122	                self.secondSeatLeftButton.heatButton.loading = YES;
123	            }
124	            if (self.carState.seatState.rightRearSeatHeat <= 0) {
125	                self.secondSeatRightButton.heatButton.loading = YES;
126	            }
127	            if ((self.carState.steerWheelState.steeringWheelHeat <= 0) && [CTMediator.defaultCarInfo.capabilities containsObject:kCarControlCapabilityWheelLoadingLinkage]) {
128	                self.wheelHeatButton.wheelButton.loading = YES;
129	            }
130	            DLogTagWarn(kAirTag, @"打开极速升温，座椅加热loading");
131	        } else {
132	            self.driverSeatButton.heatButton.loading = NO;
133	            self.passengerSeatButton.heatButton.loading = NO;
134	            self.secondSeatLeftButton.heatButton.loading = NO;
135	            self.secondSeatRightButton.heatButton.loading = NO;
136	            
137	            self.wheelHeatButton.wheelButton.loading = NO;
138	            
139	            DLogTagWarn(kAirTag, @"打开极速升温失败，座椅加热结束loading");
140	        }
141	    }];
142	    
143	    [[AirCtrlStateHelper sharedInstance].airHeatDownSignal.deliverOnMainThread subscribeNext:^(NSNumber * _Nullable x) {
144	        @strongify(self);
145	        if ([x boolValue]) {
146	            if (self.carState.seatState.driverSeatVentilation <= 0) {
147	                self.driverSeatButton.windButton.loading = YES;
148	            }
149	            if (self.carState.seatState.passengerSeatVentilation <= 0) {
150	                self.passengerSeatButton.windButton.loading = YES;
151	            }
152	            if (self.carState.seatState.leftRearSeatVentilation <= 0) {
153	                self.secondSeatLeftButton.windButton.loading = YES;
154	            }
155	            if (self.carState.seatState.rightRearSeatVentilation <= 0) {
156	                self.secondSeatRightButton.windButton.loading = YES;
157	            }
158	            DLogTagWarn(kAirTag, @"打开极速降温，座椅通风loading");
159	        } else {
160	            self.driverSeatButton.windButton.loading = NO;
161	            self.passengerSeatButton.windButton.loading = NO;
162	            self.secondSeatLeftButton.windButton.loading = NO;
163	            self.secondSeatRightButton.windButton.loading = NO;
164	            DLogTagWarn(kAirTag, @"打开极速降温失败，座椅通风结束loading");
165	        }
166	    }];
