280	- (XPSeatButtonView *)createSeatButtonWithPosttion:(SeatPostion)position seatHeat:(BOOL)seatHeat seatWind:(BOOL)seatWind backView:(UIView *)backView layoutDic:(NSDictionary *)layoutDic {
281	    XPSeatButtonView *buttonView = [[XPSeatButtonView alloc] initWithSupportSeatHeat:seatHeat seatWind:seatWind];
282	    buttonView.type = position;
283	    
284	    if ([layoutDic objectForKey:@"x"] != nil && [layoutDic objectForKey:@"y"] != nil && (seatHeat || seatWind)) {
285	        CGFloat x = [[layoutDic objectForKey:@"x"] qmui_CGFloatValue];
286	        CGFloat y = [[layoutDic objectForKey:@"y"] qmui_CGFloatValue];
287	        
288	        [backView addSubview:buttonView];
289	        [buttonView mas_makeConstraints:^(MASConstraintMaker *make) {
290	            make.size.mas_equalTo(CGSizeMake(kBtnViewWidth, kBtnViewHeight));
291	            make.centerX.mas_equalTo(backView.mas_left).offset(x*AdaptiveRatio);
292	            make.centerY.mas_equalTo(backView.mas_top).offset(y*AdaptiveRatio);
293	        }];
294	    }
295	    
296	    @weakify(self);
297	    [self.rac_deallocDisposable addDisposable:[[buttonView.heatButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
298	        @strongify(self);
299	        [self sendSeatOperatorHeat:position button:buttonView.heatButton];
300	    }]];
301	    
302	    [self.rac_deallocDisposable addDisposable:[[buttonView.windButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
303	        @strongify(self);
304	        [self sendSeatOperatorVentilate:position button:buttonView.windButton];
305	    }]];
306	    
307	    return buttonView;
308	}
