543	- (void)sendSeatOperatorHeat:(SeatPostion)direction button:(XPStateModeButton *)button {
544	    NSInteger stateMode = button.stateMode;
545	    stateMode --;
546	    if (stateMode < 0) {
547	        stateMode = 3;
548	    }
549	    DLogTagInfo(kAirTag, @"座椅加热调节指令发送 座椅位置: %@, 目标模式: %@", @(direction), @(stateMode));
550	    
551	    if (![[AirCtrlStateHelper sharedInstance] checkAirRemoteControlStatus]) {
552	        DLogTagWarn(kAirTag, @"座椅加热调节指令发送失败，手机无网或车内有人");
553	        return;
554	    }
555	
556	    button.loading = YES;
557	    @weakify(self);
558	    [[XPCarControlViewModel.sharedInstance.controlSeatHeatCommand execute:@{@"position" : @(direction), @"mode" : @(stateMode)}].deliverOnMainThread subscribeNext:^(id  _Nullable x) {
559	            
560	    } error:^(NSError * _Nullable error) {
561	        @strongify(self);
562	        DLogTagInfo(kAirTag, @"座椅加热调节失败 座椅位置: %@, 目标模式: %@", @(direction), @(stateMode));
563	        if ([error.domain isEqualToString:XPCarControlErrorDomain]) {
564	            NSString *toastMsg = @"air_connect_timeOut_tip".xpString;
565	            if (stateMode == SeatOperationModeClose) {
566	                toastMsg = @"座椅加热关闭失败";
567	            } else if (stateMode == SeatOperationModeLevel3) {
568	                toastMsg = @"座椅加热开启失败";
569	            } else {
570	                toastMsg = @"座椅加热调节失败";
571	            }
572	            [self showToastWithError:error andRevealTips:toastMsg];
573	            button.loading = NO;
574	            if (stateMode == SeatOperationModeLevel3) {
575	                [XPHvacEventTracking seatHeatTrackingWithType:(int)direction result:(error.code == XPCarControlErrorCodeMqttExecTimeout ? -1 : 0) operation:YES]; // 座椅加热埋点
576	            } else if (stateMode == SeatOperationModeClose) {
577	                [XPHvacEventTracking seatHeatTrackingWithType:(int)direction result:(error.code == XPCarControlErrorCodeMqttExecTimeout ? -1 : 0) operation:NO]; // 座椅加热埋点
578	            }
579	        }
580	    } completed:^{
581	        @strongify(self);
582	        DLogTagInfo(kAirTag, @"座椅加热调节成功 座椅位置: %@, 目标模式: %@", @(direction), @(stateMode));
583	        if (stateMode == SeatOperationModeClose) {
584	            [XPToast showMessage:@"air_seat_heat_close_success".xpString];
585	            [XPHvacEventTracking seatHeatTrackingWithType:(int)direction result:1 operation:NO]; // 座椅加热埋点
586	        } else if (stateMode == SeatOperationModeLevel3) {
587	            [XPToast showMessage:@"air_open_success_15_minutes_tip".xpString];
588	            
589	            [XPHvacEventTracking seatHeatTrackingWithType:(int)direction result:1 operation:YES]; // 座椅加热埋点
590	            
591	            // e28、d55开启加热关闭不会主动关闭座椅通风，需要app发送座椅通风关闭指令
592	            if (([CTMediator isE28] || [CTMediator isD55]) && [self frontSeatWindOpenedWithDirection:direction]) {
593	                [[XPCarControlViewModel.sharedInstance.controlSeatWindCommand execute:@{@"position" : @(direction), @"mode" : @(0)}].deliverOnMainThread subscribeNext:^(id  _Nullable x) {
594	                        
595	                } error:^(NSError * _Nullable error) {
596	                    
597	                }];
598	            }
599	        } else {
600	            // 换挡不用提示
601	        }
602	    }];
603	}
